import React, { useState } from 'react';
import { Grid, Paper, Button, Typography, TextField, Avatar } from '@mui/material';
import { makeStyles } from '@mui/styles'; 
import { useNavigate } from 'react-router-dom';
import signpng from './signupfinal.png';
import signback from './signback.png';
import logo from './logo.png';
import { ThemeProvider, createTheme } from '@mui/material/styles';

const theme = createTheme();

const useStyles = makeStyles((theme) => ({
  imageContainer: {
    position: 'relative',
  },
  image: {
    position: 'absolute',
    top: 0,
    left: 0,
    width: 'auto',
    height: '600px',
    zIndex: 2,
  },
  image2: {
    position: 'absolute',
    top: 0,
    left: 0,
    width: 'auto',
    height: '600px',
    margin: '0 0 0 10px',
    zIndex: 1,
  },
  avatarImage: {
    width: '100px',
    height: '100px',
    borderRadius: '50%',
    cursor: 'pointer',
  },
  hiddenInput: {
    display: 'none',
  },
}));

export const Signup = () => {
  const navigate = useNavigate();
  const classes = useStyles();
  const [selectedImage, setSelectedImage] = useState(null);

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <ThemeProvider theme={theme}>
      <Grid
        container
        justifyContent="center"
        alignItems="center"
        style={{ minHeight: '100vh' }}
      >
        <Paper sx={{ padding: '20px,200px,0px,0px', width: '1200px', height: '600px' }} elevation={10}>
          <Grid container>
            <Grid item xs={5} className={classes.imageContainer}>
              <img src={signpng} alt="The signup" className={classes.image} />
              <img src={signback} alt="The signup" className={classes.image2} />
            </Grid>
            <Grid item xs={7} container justifyContent="center" alignItems="center" direction='column'>
              <img src={selectedImage || logo} alt="Selected Image" className={classes.avatarImage} onClick={() => document.getElementById('avatar-input').click()} />
              <input id="avatar-input" type="file" accept="image/*" className={classes.hiddenInput} onChange={handleImageChange} />
              <Typography variant='h4' color='success' style={{ color: 'green' }}>Sign Up</Typography>
              <TextField label="Name" variant="outlined" fullWidth margin="normal" />
              <TextField label="Password" type="password" variant="outlined" fullWidth margin="normal" />
              <Button variant="contained" onClick={() => { navigate('/signup') }}>Signup</Button>
            </Grid>
          </Grid>
        </Paper>
      </Grid>
    </ThemeProvider>
  );
};
